import React, { useState } from "react";
import { Link } from "react-router-dom";
import { useLocation } from "react-router";
export const CartBlock = (props) => {
  const { cart, Products } = props;
  const [Product, setProduct] = useState([]);
  let location = useLocation();
  return (
    <>
      {location.pathname === "/category" ? (
        <div></div>
      ) : (
        <tbody>
          {Products.filter((product) => product.id === '1').map(
            (product) => (
              <tr>
                <td className="product-thumbnail">
                  <Link to="/">
                    <img
                      src={"../img/orange.jpg"}
                      alt=""
                      style={{ height: "91px", width: "82px" }}
                    />
                  </Link>
                </td>
                <td className="product-name">
                  <h4>
                    <Link to="/">{product.title}</Link>
                  </h4>
                </td>
                <td className="product-price">₹27.99 </td>
                <td className="product-quantity">
                  <div className="cart--plus--minus">
                    <form action="#" className="num-block">
                      <input
                        type="text"
                        className="in-num"
                        value={cart.quantity}
                        readonly=""
                      />
                      <div className="qtybutton-box">
                        <span className="plus">
                          <i className="fas fa-angle-up"></i>
                        </span>
                        <span className="minus dis">
                          <i className="fas fa-angle-down"></i>
                        </span>
                      </div>
                    </form>
                  </div>
                </td>
                <td className="product-subtotal">
                  <span>₹ 27.99</span>
                </td>
                <td className="product-delete">
                  <Link to="/">
                    <i className="far fa-trash-alt"></i>
                  </Link>
                </td>
              </tr>
            )
          )}
        </tbody>
      )}
    </>
  );
};
